9464         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9465     ConstantRange RCR = computeConstantRange(
9466         R1, ICmpInst::isSigned(RPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9467         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9468     // Even if L1/R1 are not both constant, we can still sometimes deduce
9469     // relationship from a single constant. For example X u> Y implies X != 0.
9470     if (auto R = isImpliedCondCommonOperandWithCR(LPred, LCR, RPred, RCR))
